power_of <- function(exp) {
  force(exp)                 # avoid lazy-eval surprises
  function(x) x^exp
}

square <- power_of(2)
cube <- power_of(3)
square(4)   # 16
cube(2)     # 8

# Stateful counter via closure
counter <- function() {
  n <- 0
  function() { n <<- n + 1; n }
}
next_id <- counter()
next_id(); next_id()   # 1 then 2
